#include <stdio.h>

#define N 3

/* FCFS (First Come First Served) non-preemptif avec arrivees echelonnees.
 * Algorithme :
 *   Pour chaque processus i (dans l'ordre d'arrivee) :
 *     1. Si le CPU est idle (time < arrival[i]), avancer : time = arrival[i]
 *     2. Executer le burst : time += burst[i]
 *     3. Enregistrer : completion[i] = time
 */
void simulate_fcfs(int burst[], int arrival[], int n, int completion[]) {
    int time = 0;
    for (int i = 0; i < n; i++) {
        /* Etape 1 : si le CPU finit avant l'arrivee, on attend */
        if (time < arrival[i])
            time = arrival[i];  /* <-- avancer au temps d'arrivee */
        /* Etape 2 : executer le burst */
        time += burst[i];
        /* Etape 3 : enregistrer le temps de completion */
        completion[i] = time;
    }
}

int main(void) {
    int burst[]   = {4, 3, 1};
    int arrival[] = {0, 1, 2};
    int completion[N];
    simulate_fcfs(burst, arrival, N, completion);
    for (int i = 0; i < N; i++)
        printf("P%d completion: %d\n", i + 1, completion[i]);
    return 0;
}

