#include <stdio.h>
#define N 3

void simulate_fcfs(int burst[], int arrival[], int n, int completion[]) {
    int time = 0;
    for (int i = 0; i < n; i++) {
        if (time < arrival[i])
            time = arrival[i];
        time += burst[i];
        completion[i] = time;
    }
}

int main(void) {
    int burst[]   = {4, 3, 1};
    int arrival[] = {0, 1, 2};
    int completion[N];
    simulate_fcfs(burst, arrival, N, completion);
    for (int i = 0; i < N; i++)
        printf("P%d completion: %d\n", i + 1, completion[i]);
    return 0;
}
